const resp = $input.first().json;
const stdout = resp.stdout || '';
const ok = resp.ok === true;
const duracion = resp.duracion_s ? `${Math.floor(resp.duracion_s/60)}m ${resp.duracion_s%60}s` : 'N/D';

const candidatosMatch = stdout.match(/Without reply > \d+ days\s*:\s*(\d+)/);
const enviadosMatch   = stdout.match(/Follow-ups OK\s*:\s*(\d+)/);
const erroresMatch    = stdout.match(/Errors\/Bounces\s*:\s*(\d+)/);

const candidatos = candidatosMatch ? parseInt(candidatosMatch[1]) : 0;
const enviados   = enviadosMatch   ? parseInt(enviadosMatch[1])   : 0;
const errores    = erroresMatch    ? parseInt(erroresMatch[1])    : 0;

const fecha = new Date().toLocaleString('es-ES', {timeZone: 'Europe/Madrid'});
let message = null;

if (!ok) {
  message = `❌ <b>Error en seguimiento</b>\n📅 ${fecha}\n\n<pre>${(resp.stderr||stdout).slice(-400)}</pre>`;
} else if (enviados > 0) {
  const ico = errores > 0 ? '⚠️' : '✅';
  message = `${ico} <b>Seguimiento automático completado</b>\n📅 ${fecha}\n\n` +
            `🔍 Candidatos sin respuesta: ${candidatos}\n` +
            `✉️ Seguimientos enviados: <b>${enviados}</b>\n` +
            `❌ Errores: ${errores}\n` +
            `⏱ Tiempo: ${duracion}`;
}
// Si enviados===0 y sin error → message=null → IF lo filtra
return [{ json: { message, ok, candidatos, enviados, hayQueNotificar: message !== null } }];
